using System.Collections.Generic;
using UnityEngine;

/// <summary>
/// Base de dados central para resolver assets (ScriptableObjects) a partir do
/// respectivo ID (worldId/areaId/formId/itemId/upgradeId). Necessária porque o
/// sistema de Save (Etapa de Save) guarda apenas IDs em texto — as referências
/// a ScriptableObject não podem ser serializadas em JSON.
///
/// SETUP: cria UM asset deste tipo em "Assets/Resources/GameDatabase.asset"
/// ("Create &gt; Animals &gt; Game Database") e arrasta para as listas abaixo
/// todos os WorldData/AreaData/AnimalFormData/ItemData/UpgradeData do jogo.
/// Só este asset precisa de estar dentro de uma pasta "Resources" — os
/// restantes podem ficar onde já estão.
/// </summary>
[CreateAssetMenu(menuName = "Animals/Game Database", fileName = "GameDatabase")]
public class GameDatabase : ScriptableObject
{
    private const string ResourcesPath = "GameDatabase";

    private static GameDatabase _instance;

    /// <summary>Carrega (uma vez) e devolve o GameDatabase em Resources/GameDatabase. Null se não existir.</summary>
    public static GameDatabase Instance
    {
        get
        {
            if (_instance == null)
                _instance = Resources.Load<GameDatabase>(ResourcesPath);

            return _instance;
        }
    }

    [Header("Mundos e Áreas")]
    public List<WorldData> worlds = new List<WorldData>();
    public List<AreaData> areas = new List<AreaData>();

    [Header("Formas de Animais")]
    public List<AnimalFormData> animalForms = new List<AnimalFormData>();

    [Header("Itens e Upgrades")]
    public List<ItemData> items = new List<ItemData>();
    public List<UpgradeData> upgrades = new List<UpgradeData>();

    [Header("Missões e Emblemas")]
    public List<MissionData> missions = new List<MissionData>();
    public List<EmblemData> emblems = new List<EmblemData>();

    public WorldData FindWorld(string worldId)
    {
        if (string.IsNullOrEmpty(worldId)) return null;
        foreach (var w in worlds)
            if (w != null && w.worldId == worldId) return w;
        return null;
    }

    public AreaData FindArea(string areaId)
    {
        if (string.IsNullOrEmpty(areaId)) return null;
        foreach (var a in areas)
            if (a != null && a.areaId == areaId) return a;
        return null;
    }

    public AnimalFormData FindAnimalForm(string formId)
    {
        if (string.IsNullOrEmpty(formId)) return null;
        foreach (var f in animalForms)
            if (f != null && f.formId == formId) return f;
        return null;
    }

    public ItemData FindItem(string itemId)
    {
        if (string.IsNullOrEmpty(itemId)) return null;
        foreach (var i in items)
            if (i != null && i.itemId == itemId) return i;
        return null;
    }

    public UpgradeData FindUpgrade(string upgradeId)
    {
        if (string.IsNullOrEmpty(upgradeId)) return null;
        foreach (var u in upgrades)
            if (u != null && u.upgradeId == upgradeId) return u;
        return null;
    }

    public MissionData FindMission(string missionId)
    {
        if (string.IsNullOrEmpty(missionId)) return null;
        foreach (var m in missions)
            if (m != null && m.missionId == missionId) return m;
        return null;
    }

    public EmblemData FindEmblem(string emblemId)
    {
        if (string.IsNullOrEmpty(emblemId)) return null;
        foreach (var e in emblems)
            if (e != null && e.emblemId == emblemId) return e;
        return null;
    }
}
